type User = {
    id: number;
    name: string;
    email: string;
};

class UserManager {
    private users: User[] = [];

    addUser(user: User): void {
        this.users.push(user);
    }

    getUserById(id: number): User | undefined {
        return this.users.find(user => user.id === id);
    }

    removeUser(id: number): void {
        this.users = this.users.filter(user => user.id !== id);
    }
}

